#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <iostream>
#include <ctime>
#include <cassert>

#define HALO     1
#define STR_SIZE 256
#define DEVICE   0
#define M_SEED   9

#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))
#define CLAMP_RANGE(x, min, max) x = (x < (min)) ? min : ((x > (max)) ? max : x)
#define MIN(a, b) ((a) <= (b) ? (a) : (b))

// Kernel prototype declaration
__global__ void dynproc_kernel(int iteration,
                               const int* __restrict__ gpuWall,
                               const int* __restrict__ gpuSrc,
                               int* gpuResults,
                               int cols,
                               int rows,
                               int startStep,
                               int border,
                               int HALO,
                               int* outputBuffer);

int main(int argc, char** argv)
{
    int rows = -1, cols = -1;
    int pyramid_height = -1;
    int verbose = 0;

    // Parse command line arguments
    for (int cur_arg = 1; cur_arg < argc; cur_arg++)
    {
        if (strcmp(argv[cur_arg], "-c") == 0)
        {
            if (argc >= cur_arg + 1)
            {
                cols = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-r") == 0)
        {
            if (argc >= cur_arg + 1)
            {
                rows = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-h") == 0)
        {
            if (argc >= cur_arg + 1)
            {
                pyramid_height = atoi(argv[cur_arg + 1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-v") == 0)
        {
            verbose = 1;
        }
    }

    if (cols < 0 || rows < 0 || pyramid_height < 0)
    {
        fprintf(stderr, "usage: %s <-r rows> <-c cols> <-h pyramid_height> [-v]\n", argv[0]);
        exit(0);
    }

    int size = rows * cols;
    int borderCols = pyramid_height * HALO;

    int* data = new int[size];
    int** wall = new int*[rows];
    for (int n = 0; n < rows; n++)
    {
        wall[n] = data + cols * n;
    }
    int* result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }

    int* d_gpuWall;
    int* d_gpuResult[2];
    int* d_outputBuffer;

    cudaMalloc((void**)&d_gpuWall, sizeof(int) * (size - cols));
    cudaMalloc((void**)&d_gpuResult[0], sizeof(int) * cols);
    cudaMalloc((void**)&d_gpuResult[1], sizeof(int) * cols);
    cudaMalloc((void**)&d_outputBuffer, sizeof(int) * 16384);

    cudaMemcpy(d_gpuWall, data + cols, sizeof(int) * (size - cols), cudaMemcpyHostToDevice);
    cudaMemcpy(d_gpuResult[0], data, sizeof(int) * cols, cudaMemcpyHostToDevice);

    int* h_outputBuffer = (int*)malloc(16384 * sizeof(int));
    for (int i = 0; i < 16384; i++)
    {
        h_outputBuffer[i] = 0;
    }
    cudaMemcpy(d_outputBuffer, h_outputBuffer, sizeof(int) * 16384, cudaMemcpyHostToDevice);

    int src = 1, final_ret = 0;

    // Determine block size and grid size
    int BLOCK_SIZE = 256; // default block size
    int small_block_cols = BLOCK_SIZE - (pyramid_height * HALO * 2);
    int grid_size = (cols + small_block_cols - 1) / small_block_cols;

    size_t shared_mem_size = 2 * BLOCK_SIZE * sizeof(int);

    for (int t = 0; t < rows - 1; t += pyramid_height)
    {
        int temp = src;
        src = final_ret;
        final_ret = temp;

        int arg0 = MIN(pyramid_height, rows - t - 1);
        int theHalo = HALO;

        dynproc_kernel<<<grid_size, BLOCK_SIZE, shared_mem_size>>>(
            arg0,
            d_gpuWall,
            d_gpuResult[src],
            d_gpuResult[final_ret],
            cols,
            rows,
            t,
            borderCols,
            theHalo,
            d_outputBuffer);

        cudaDeviceSynchronize();
    }

    cudaMemcpy(result, d_gpuResult[final_ret], sizeof(int) * cols, cudaMemcpyDeviceToHost);
    cudaMemcpy(h_outputBuffer, d_outputBuffer, sizeof(int) * 16384, cudaMemcpyDeviceToHost);

    h_outputBuffer[16383] = '\0';

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
        printf("%d ", data[i]);
    printf("\n");
    for (int i = 0; i < cols; i++)
        printf("%d ", result[i]);
    printf("\n");
#endif

    cudaFree(d_gpuWall);
    cudaFree(d_gpuResult[0]);
    cudaFree(d_gpuResult[1]);
    cudaFree(d_outputBuffer);

    delete[] data;
    delete[] wall;
    delete[] result;
    free(h_outputBuffer);

    return EXIT_SUCCESS;
}

__global__ void dynproc_kernel(int iteration,
                               const int* __restrict__ gpuWall,
                               const int* __restrict__ gpuSrc,
                               int* gpuResults,
                               int cols,
                               int rows,
                               int startStep,
                               int border,
                               int HALO,
                               int* outputBuffer)
{
    extern __shared__ int shared_mem[];
    int* prev = shared_mem;
    int* result = shared_mem + blockDim.x;

    int BLOCK_SIZE = blockDim.x;
    int bx = blockIdx.x;
    int tx = threadIdx.x;

    int small_block_cols = BLOCK_SIZE - (iteration * HALO * 2);

    int blkX = (small_block_cols * bx) - border;
    int blkXmax = blkX + BLOCK_SIZE - 1;

    int xidx = blkX + tx;

    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (blkXmax > cols - 1) ? BLOCK_SIZE - 1 - (blkXmax - cols + 1) : BLOCK_SIZE - 1;

    int W = tx - 1;
    int E = tx + 1;

    W = (W < validXmin) ? validXmin : W;
    E = (E > validXmax) ? validXmax : E;

    bool isValid = IN_RANGE(tx, validXmin, validXmax);

    if (IN_RANGE(xidx, 0, cols - 1))
    {
        prev[tx] = gpuSrc[xidx];
    }

    __syncthreads();

    bool computed = false;
    for (int i = 0; i < iteration; i++)
    {
        computed = false;

        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && isValid)
        {
            computed = true;
            int left = prev[W];
            int up = prev[tx];
            int right = prev[E];
            int shortest = MIN(left, up);
            shortest = MIN(shortest, right);

            int index = cols * (startStep + i) + xidx;
            result[tx] = shortest + gpuWall[index];

            if (tx == 11 && i == 0)
            {
                int bufIndex = gpuSrc[xidx];
                outputBuffer[bufIndex] = 1;
            }
        }

        __syncthreads();

        if (i == iteration - 1)
        {
            break;
        }

        if (computed)
        {
            prev[tx] = result[tx];
        }
        __syncthreads();
    }

    if (computed)
    {
        gpuResults[xidx] = result[tx];
    }
}
